import React, { useEffect, useMemo, useState } from "react";
import axios from "axios";
import { BookingRecord } from "../types";

const API_BASES = ["http://localhost:5000/api", "http://127.0.0.1:5000/api"];

const Bookings: React.FC = () => {
  const [bookings, setBookings] = useState<BookingRecord[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [query, setQuery] = useState("");

  const fetchBookings = async () => {
    setLoading(true);
    setError("");

    for (const base of API_BASES) {
      try {
        const response = await axios.get<BookingRecord[]>(`${base}/bookings`);
        setBookings(response.data);
        setLoading(false);
        return;
      } catch (fetchError) {
        console.error(`Failed to fetch bookings from ${base}`, fetchError);
      }
    }

    setError("Could not load bookings. Start backend with: cd backend && node server.js");
    setLoading(false);
  };

  useEffect(() => {
    fetchBookings();
  }, []);

  const filteredBookings = useMemo(() => {
    const q = query.trim().toLowerCase();
    if (!q) return bookings;

    return bookings.filter((booking) => {
      return (
        booking.id.toLowerCase().includes(q) ||
        booking.busName.toLowerCase().includes(q) ||
        booking.route.toLowerCase().includes(q) ||
        booking.passengerDetails.some((p) => p.name.toLowerCase().includes(q))
      );
    });
  }, [bookings, query]);

  const totalRevenue = useMemo(() => {
    return bookings.reduce((sum, booking) => sum + booking.totalPrice, 0);
  }, [bookings]);

  const todaysBookings = useMemo(() => {
    const today = new Date().toDateString();
    return bookings.filter((b) => new Date(b.bookedAt).toDateString() === today).length;
  }, [bookings]);

  return (
    <section>
      <div className="mb-5 flex flex-wrap items-center justify-between gap-3">
        <h2 className="text-2xl font-bold text-slate-900">All Bookings</h2>
        <button
          type="button"
          onClick={fetchBookings}
          className="rounded-lg border border-slate-300 px-3 py-2 text-sm font-semibold text-slate-700 hover:bg-slate-100"
        >
          Refresh
        </button>
      </div>

      <div className="mb-5 grid gap-3 sm:grid-cols-3">
        <div className="rounded-xl bg-white p-4 shadow-travel ring-1 ring-slate-200">
          <p className="text-xs uppercase text-slate-500">Total Bookings</p>
          <p className="mt-1 text-2xl font-bold text-slate-900">{bookings.length}</p>
        </div>
        <div className="rounded-xl bg-white p-4 shadow-travel ring-1 ring-slate-200">
          <p className="text-xs uppercase text-slate-500">Today</p>
          <p className="mt-1 text-2xl font-bold text-slate-900">{todaysBookings}</p>
        </div>
        <div className="rounded-xl bg-white p-4 shadow-travel ring-1 ring-slate-200">
          <p className="text-xs uppercase text-slate-500">Total Revenue</p>
          <p className="mt-1 text-2xl font-bold text-slate-900">INR {totalRevenue}</p>
        </div>
      </div>

      <div className="mb-5 rounded-xl bg-white p-4 shadow-travel ring-1 ring-slate-200">
        <input
          type="text"
          placeholder="Search by booking ID, bus, route, passenger"
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          className="w-full rounded-lg border border-slate-300 px-3 py-2 text-sm outline-none focus:border-blue-500"
        />
      </div>

      {loading ? <p className="text-slate-600">Loading bookings...</p> : null}
      {!loading && error ? (
        <div className="rounded-xl bg-red-50 p-6 text-center text-red-700 shadow-travel ring-1 ring-red-200">{error}</div>
      ) : null}
      {!loading && !error && filteredBookings.length === 0 ? (
        <div className="rounded-xl bg-white p-6 text-center text-slate-600 shadow-travel ring-1 ring-slate-200">
          No bookings found.
        </div>
      ) : null}

      <div className="grid gap-4">
        {filteredBookings.map((booking) => (
          <article key={booking.id} className="rounded-2xl bg-white p-5 shadow-travel ring-1 ring-slate-200">
            <div className="flex flex-wrap items-start justify-between gap-3">
              <div>
                <h3 className="text-lg font-bold text-slate-900">{booking.busName}</h3>
                <p className="text-sm text-slate-600">{booking.route}</p>
                <p className="mt-1 text-xs text-slate-500">Booking ID: {booking.id}</p>
              </div>
              <p className="rounded-full bg-emerald-100 px-3 py-1 text-xs font-semibold text-emerald-700">{booking.paymentMethod}</p>
            </div>

            <div className="mt-4 grid gap-2 text-sm text-slate-700 md:grid-cols-2">
              <p>
                <span className="font-medium">Seats:</span> {booking.selectedSeats.join(", ")}
              </p>
              <p>
                <span className="font-medium">Passengers:</span> {booking.passengerDetails.map((p) => p.name).join(", ")}
              </p>
              <p>
                <span className="font-medium">Total:</span> INR {booking.totalPrice}
              </p>
              <p>
                <span className="font-medium">Booked At:</span> {new Date(booking.bookedAt).toLocaleString()}
              </p>
            </div>
          </article>
        ))}
      </div>
    </section>
  );
};

export default Bookings;
